INSERT INTO TB_AREA(
    area_name,
    area_cd,
    area_zip_no,
    area_addr,
    area_dtl_addr,
    area_latitude,
    area_longitude,
    area_desc,
    use_flag,
    rgst_user_id,
    rgst_date_time,
    upt_user_id,
    upt_date_time
) VALUES(
    #{areaName}
    ,#{areaCd}
    ,#{areaZipNo}
    ,#{areaAddr}
    ,#{areaDtlAddr}
    ,#{areaLatitude}
    ,#{areaLongitude}
    ,#{areaDesc}
    ,#{useFlag}
    ,#{rgstUserId}
    ,NOW()
    ,#{uptUserId}
    ,NOW()
)

mapper.update:
UPDATE TB_AREA
SET area_name = #{areaName}
    ,area_cd = #{areaCd}
    ,area_zip_no = #{areaZipNo}
    ,area_addr = #{areaAddr}
    ,area_dtl_addr = #{areaDtlAddr}
    ,area_latitude = #{areaLatitude}
    ,area_longitude = #{areaLongitude}
    ,area_desc = #{areaDesc}
    ,use_flag = #{useFlag}
    ,upt_date_time = now()
    ,upt_user_id = #{uptUserId}
WHERE area_seq = #{areaSeq}
